// registerGridStyle returns the CSS grid-template-columns value based on provider count.
func registerGridStyle(providers []auth.Authenticator) string {
	n := len(providers)
	if n <= 1 {
		return "grid-template-columns: 1fr"
	}
	if n == 2 {
		return "grid-template-columns: repeat(2, minmax(0, 1fr))"
	}
	return "grid-template-columns: repeat(3, minmax(0, 1fr))"
}

